// 1. Get all incoming items
const items = $input.all();

// 2. Extract common metadata from the first item (assuming it's passed along)
// We use optional chaining ?. to prevent crashes if these don't exist
const firstItem = items[0]?.json || {};
const issueBody = firstItem.body || '';
const issueTitle = firstItem.title || '';
const issueUrl = firstItem.html_url || firstItem.url || '';

// 3. Filter and Map the items
// We only want items that look like Python code (contain 'def ')
return items
  .filter(item => {
    const content = item.json.data || "";
    return content.includes('def '); // Only keep items with Python functions
  })
  .map(item => {
    const rawContent = item.json.data;

    // Detect a filename from comments or default to app.py
    // (e.g., if the code starts with # app.py)
    const fileNameMatch = rawContent.match(/^#\s*([\w\.-]+)/);
    const filename = fileNameMatch ? fileNameMatch[1] : 'app.py';

    return {
      json: {
        filename: filename,
        code: rawContent,
        body: issueBody,
        title: issueTitle,
        url: issueUrl
      }
    };
  });

// Get the PR URL from the incoming JSON
const prUrl = $input.first().json.body.pull_request.url;
const filesUrl = `${prUrl}/files`;

try {
  // Use n8n's built-in HTTP helper
  const response = await this.helpers.request({
    method: 'GET',
    url: filesUrl,
    headers: {
      'Accept': 'application/vnd.github+json',
      'User-Agent': 'n8n-workflow', // GitHub requires a User-Agent header
      'X-GitHub-Api-Version': '2022-11-28'
    },
    json: true // Automatically parses the JSON response
  });

  // Map the files to a cleaner format
  const changedFiles = response.map(file => ({
    filename: file.filename,
    status: file.status,
    additions: file.additions,
    deletions: file.deletions,
    patch: file.patch // This contains the actual code changes
  }));

  return {
    files: changedFiles
  };

} catch (error) {
  return {
    error: error.message,
    details: "Check if the repository is private or if you hit GitHub rate limits."
  };
}

const sourceCode = $('Extract from File').first().json.data;
let aiOutput = $input.first().json.output || "";

// Remove think blocks and markdown fences
aiOutput = aiOutput.replace(/<think>[\s\S]*?<\/think>/g, '');
aiOutput = aiOutput.replace(/```(?:python|json)?\n?/g, '').replace(/```/g, '');

const jsonMatch = aiOutput.match(/\[[\s\S]*\]|\{[\s\S]*\}/);
if (!jsonMatch) throw new Error("Could not find any JSON structure in AI response.");

let parsedData;
try {
    parsedData = JSON.parse(jsonMatch[0]);
} catch (e) {
    throw new Error("AI returned malformed JSON: " + e.message);
}

const testCases = Array.isArray(parsedData) ? parsedData : [parsedData];

return testCases.map((tc, index) => {
    const code = tc.test_code || tc.code || "";
    const description = tc.description || tc.desc || `Test Case ${index + 1}`;
    const id = (tc.id || `TC${index + 1}`).toString().replace(/[^a-zA-Z0-9]/g, '_');
    // ✅ FIX: Strip out the execution block so it doesn't run during pytest collection
    const sanitizedSource = sourceCode.replace(/if\s+(__name__|_name_)\s+==\s+["'](__main__|_main_)["']\s*:\s*[\s\S]*$/gm, "");
    // ✅ SIMPLE: Just define the source functions directly, no importlib
    const finalPythonScript = `import pytest
from unittest.mock import patch

${sanitizedSource}

${code}
`.trim();

    return {
        json: {
            id: id,
            description: description,
            test_code_b64: Buffer.from(finalPythonScript).toString('base64')
        }
    };
});

const out = $json.stdout || "";
const err = $json.stderr || "";
const fullOutput = out + err;

const description = $node["Loop Over Tests"].json.description || 'General Logic Test';

let status = 'FAILED';
let errorDetail = "Unknown Error";

if (fullOutput.includes('PASSED')) {
    status = 'PASSED';
    errorDetail = "Success";
} else {
    // This captures the actual Python traceback instead of a generic message
    const lines = fullOutput.split('\n');
    errorDetail = lines.slice(-3).join(' ').substring(0, 300) || "Check Terminal: Command Failed";
}

return [{
    json: {
        id: $node["Loop Over Tests"].json.id,
        description: description,
        status: status,
        output: errorDetail
    }
}];

// Get all results from the Aggregate node
const results = $json.data; 

let html = `
<h2>QA Test Report</h2>
<table border="1" cellpadding="5" cellspacing="0">
<tr style="background-color: #f2f2f2;">
  <th>No</th>
  <th>ID</th>
  <th>Test Description</th>
  <th>Status</th>
  <th>Output</th>
</tr>
`;

results.forEach((r, i) => {
  const color = r.status === 'PASSED' ? 'green' : 'red';
  html += `
  <tr>
    <td>${i + 1}</td>
    <td><b>${r.id || 'N/A'}</b></td>
    <td>${r.description || 'N/A'}</td>
    <td style="color: ${color}; font-weight: bold;">${r.status || 'FAILED'}</td>
    <td><pre>${(r.output || 'No output').replace(/</g, '&lt;')}</pre></td>
  </tr>`;
});

html += `</table>`;

return [{ json: { email_html: html } }];

// 1. Get all incoming items
const items = $input.all();

// 2. Extract specific data points from the known items
// Item 0 contains the URL
const issueUrl = items[0]?.json["body.issue.url"] || "";

// Item 1 contains the HTML report
const emailHtml = items[1]?.json["email_html"] || "";

// 3. Create a single combined output
// We wrap the URL in a clickable HTML link to append it to the report
const finalHtml = `
  ${emailHtml}
`;

return [
  {
    json: {
      url: issueUrl,
      html_report: finalHtml
    }
  }
];
